import { isProduction, logger } from "../../../4942.js";
import { modifyConfigWithAutoNavSide } from "../../auto-nav-sidebar/index.js";
import { createSiteData } from "./createSiteData.js";
const siteDataVMPlugin = (context)=>{
    const { config, pluginDriver } = context;
    let siteDataModulePromise;
    const createSiteDataModule = async (metaFileSet = new Set(), mdFileSet = new Set())=>{
        const force = !pluginDriver.haveNavSidebarConfig;
        const now = performance.now();
        try {
            await modifyConfigWithAutoNavSide(config, metaFileSet, mdFileSet, force);
        } finally{
            logger.debug(`modifyConfigWithAutoNavSide - size: ${mdFileSet.size} cost: ${performance.now() - now}ms`);
        }
        const { siteData } = await createSiteData(config);
        return {
            code: `export default ${JSON.stringify(siteData, null, 2)}`,
            metaFileSet,
            mdFileSet
        };
    };
    const getSiteDataModule = (metaFileSet, mdFileSet)=>{
        if (!isProduction()) return createSiteDataModule(metaFileSet, mdFileSet);
        siteDataModulePromise ??= createSiteDataModule(metaFileSet, mdFileSet).catch((error)=>{
            siteDataModulePromise = void 0;
            throw error;
        });
        return siteDataModulePromise;
    };
    const addSiteDataDependencies = (addDependency, metaFileSet, mdFileSet)=>{
        for (const metaFile of metaFileSet)addDependency(metaFile);
        for (const mdFile of mdFileSet)addDependency(mdFile);
    };
    return {
        ["virtual-site-data"]: async ({ addDependency })=>{
            const metaFileSet = new Set();
            const mdFileSet = new Set();
            let siteDataModule;
            try {
                siteDataModule = await getSiteDataModule(metaFileSet, mdFileSet);
                return siteDataModule.code;
            } finally{
                addSiteDataDependencies(addDependency, siteDataModule?.metaFileSet ?? metaFileSet, siteDataModule?.mdFileSet ?? mdFileSet);
            }
        }
    };
};
export { siteDataVMPlugin };
